/**
 * Audit logging service for notification dispatch.
 *
 * Records every notification that is dispatched through the system,
 * including the channel used, priority level, and timestamp.
 * This provides a complete audit trail for compliance and debugging.
 */

import type { NotificationPriority } from '../events/event-types.js';
import type { Notification } from './notification.service.js';

export interface AuditEntry {
  notificationId: string;
  recipient: string;
  channel: string;
  priority: NotificationPriority;
  subject: string;
  timestamp: Date;
  routingReason: 'priority' | 'user-preference';
}

export class AuditService {
  private entries: AuditEntry[] = [];

  /**
   * Record a notification dispatch in the audit log.
   */
  record(entry: AuditEntry): void {
    this.entries.push({ ...entry });
  }

  /**
   * Get all audit entries.
   */
  getEntries(): AuditEntry[] {
    return [...this.entries];
  }

  /**
   * Get audit entries for a specific recipient.
   */
  getEntriesForRecipient(recipient: string): AuditEntry[] {
    return this.entries.filter((e) => e.recipient === recipient);
  }

  /**
   * Get audit entries for a specific channel.
   */
  getEntriesForChannel(channel: string): AuditEntry[] {
    return this.entries.filter((e) => e.channel === channel);
  }

  /**
   * Get audit entries for a specific notification ID.
   */
  getEntryByNotificationId(notificationId: string): AuditEntry | undefined {
    return this.entries.find((e) => e.notificationId === notificationId);
  }

  /**
   * Clear all audit entries (useful for testing).
   */
  clear(): void {
    this.entries = [];
  }
}

/**
 * Notification preferences service.
 *
 * Allows per-user channel preferences that override the priority router.
 * When a user has a channel preference set, notifications are delivered
 * through that channel regardless of priority level.
 */

export class NotificationPreferencesService {
  private preferences = new Map<string, string>();

  /**
   * Set a user's preferred notification channel.
   * This overrides priority-based routing for the user.
   */
  setPreference(userId: string, channelName: string): void {
    this.preferences.set(userId, channelName);
  }

  /**
   * Get a user's preferred notification channel, if set.
   */
  getPreference(userId: string): string | undefined {
    return this.preferences.get(userId);
  }

  /**
   * Remove a user's channel preference, reverting to priority-based routing.
   */
  removePreference(userId: string): void {
    this.preferences.delete(userId);
  }

  /**
   * Check whether a user has a channel preference set.
   */
  hasPreference(userId: string): boolean {
    return this.preferences.has(userId);
  }

  /**
   * Get all stored preferences (useful for testing).
   */
  getAllPreferences(): Map<string, string> {
    return new Map(this.preferences);
  }

  /**
   * Clear all preferences (useful for testing).
   */
  clear(): void {
    this.preferences.clear();
  }
}

