export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private channels: NotificationChannel[] = [];
  private priorityRouter?: PriorityRouter;
  private auditService?: AuditService;
  private preferencesService?: NotificationPreferencesService;
  private routingConfigured = false;

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Configure priority-based routing with optional user preferences and audit logging.
   * When configured, notifications are routed by priority (or user preference override)
   * instead of being broadcast to all channels.
   */
  configurePriorityRouting(options: {
    priorityRouter: PriorityRouter;
    auditService?: AuditService;
    preferencesService?: NotificationPreferencesService;
  }): void {
    this.priorityRouter = options.priorityRouter;
    this.auditService = options.auditService;
    this.preferencesService = options.preferencesService;
    this.routingConfigured = true;

    this.eventBus.on<NotificationSendEvent>('notification:send', (event) => {
      const notification: Notification = {
        id: generateNotificationId(),
        recipient: event.recipient,
        subject: event.subject,
        body: event.body,
        sentAt: event.timestamp,
      };
      this.notifications.push(notification);

      let channel: NotificationChannel | undefined;
      let routingReason: 'priority' | 'user-preference' = 'priority';

      // Check user preferences first
      if (this.preferencesService) {
        const preferredChannel = this.preferencesService.getPreference(event.recipient);
        if (preferredChannel) {
          channel = this.channels.find((c) => c.name === preferredChannel);
          if (channel) {
            routingReason = 'user-preference';
          }
        }
      }

      // Fall back to priority routing
      if (!channel && this.priorityRouter) {
        channel = this.priorityRouter.getChannelForPriority(event.priority);
      }

      if (channel) {
        channel.send(notification);
        this.logger.info(
          `Notification ${notification.id} routed via ${channel.name} (${routingReason}) to ${notification.recipient}`,
        );

        // Record audit entry
        if (this.auditService) {
          this.auditService.record({
            notificationId: notification.id,
            recipient: event.recipient,
            channel: channel.name,
            priority: event.priority,
            subject: event.subject,
            timestamp: event.timestamp,
            routingReason,
          });
        }
      } else {
        this.logger.info(
          `No channel found for notification ${notification.id} (priority: ${event.priority})`,
        );
      }
    });
  }

  /**
   * Register a notification channel. When priority routing is not configured,
   * the channel subscribes to notification:send events and delivers each notification.
   * When priority routing is configured, channels are stored for lookup by name.
   */
  addChannel(channel: NotificationChannel): void {
    this.channels.push(channel);

    if (!this.routingConfigured) {
      this.eventBus.on<NotificationSendEvent>('notification:send', (event) => {
        const notification: Notification = {
          id: generateNotificationId(),
          recipient: event.recipient,
          subject: event.subject,
          body: event.body,
          sentAt: event.timestamp,
        };
        this.notifications.push(notification);
        channel.send(notification);
        this.logger.info(
          `Notification ${notification.id} delivered via ${channel.name} to ${notification.recipient}`,
        );
      });
    }
  }

