import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  EmailNotificationChannel,
  SmsNotificationChannel,
  WebhookNotificationChannel,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { PriorityRouter } from '../../src/services/priority-router.js';
import { AuditService } from '../../src/services/audit.service.js';
import { NotificationPreferencesService } from '../../src/services/notification-preferences.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import type {
  OrderCreatedEvent,
  NotificationSendEvent,
} from '../../src/events/event-types.js';

describe('Notification Integration', () => {
  let eventBus: EventBus;
  let service: NotificationService;
  let emailChannel: EmailNotificationChannel;
  let smsChannel: SmsNotificationChannel;
  let webhookChannel: WebhookNotificationChannel;
  let priorityRouter: PriorityRouter;
  let auditService: AuditService;
  let preferencesService: NotificationPreferencesService;

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    resetNotificationIdCounter();

    emailChannel = new EmailNotificationChannel();
    smsChannel = new SmsNotificationChannel();
    webhookChannel = new WebhookNotificationChannel('https://hooks.example.com/notify');

    priorityRouter = new PriorityRouter();
    priorityRouter.registerRoute('urgent', smsChannel);
    priorityRouter.registerRoute('normal', emailChannel);
    priorityRouter.registerRoute('low', webhookChannel);

    auditService = new AuditService();
    preferencesService = new NotificationPreferencesService();

    service = new NotificationService(eventBus);
    service.configurePriorityRouting({
      priorityRouter,
      auditService,
      preferencesService,
    });
    service.addChannel(emailChannel);
    service.addChannel(smsChannel);
    service.addChannel(webhookChannel);
  });

  describe('priority-based routing', () => {
    it('should route urgent notifications to SMS', async () => {
      await eventBus.emit<NotificationSendEvent>({
        type: 'notification:send',
        recipient: 'alice@example.com',
        subject: 'Urgent Alert',
        body: 'Your account has been compromised',
        priority: 'urgent',
        timestamp: new Date(),
      });

      expect(smsChannel.getSentMessages()).toHaveLength(1);
      expect(smsChannel.getSentMessages()[0]?.subject).toBe('Urgent Alert');
      expect(emailChannel.getSentEmails()).toHaveLength(0);
      expect(webhookChannel.getDeliveries()).toHaveLength(0);
    });

    it('should route normal notifications to email', async () => {
      await eventBus.emit<NotificationSendEvent>({
        type: 'notification:send',
        recipient: 'bob@example.com',
        subject: 'Order Update',
        body: 'Your order has shipped',
        priority: 'normal',
        timestamp: new Date(),
      });

      expect(emailChannel.getSentEmails()).toHaveLength(1);
      expect(emailChannel.getSentEmails()[0]?.subject).toBe('Order Update');
      expect(smsChannel.getSentMessages()).toHaveLength(0);
      expect(webhookChannel.getDeliveries()).toHaveLength(0);
    });

    it('should route low-priority notifications to webhook', async () => {
      await eventBus.emit<NotificationSendEvent>({
        type: 'notification:send',
        recipient: 'system@example.com',
        subject: 'Daily Summary',
        body: 'Here is your daily report',
        priority: 'low',
        timestamp: new Date(),
      });

      expect(webhookChannel.getDeliveries()).toHaveLength(1);
      expect(webhookChannel.getDeliveries()[0]?.notification.subject).toBe('Daily Summary');
      expect(emailChannel.getSentEmails()).toHaveLength(0);
      expect(smsChannel.getSentMessages()).toHaveLength(0);
    });
  });

  describe('user preference override', () => {
    it('should override priority routing when user has a preference', async () => {
      preferencesService.setPreference('alice@example.com', 'sms');

      await eventBus.emit<NotificationSendEvent>({
        type: 'notification:send',
        recipient: 'alice@example.com',
        subject: 'Normal Notification',
        body: 'This would normally go to email',
        priority: 'normal',
        timestamp: new Date(),
      });

      // Should go to SMS (user preference) instead of email (priority routing)
      expect(smsChannel.getSentMessages()).toHaveLength(1);
      expect(emailChannel.getSentEmails()).toHaveLength(0);
    });

    it('should use priority routing when user has no preference', async () => {
      // No preference set for bob
      await eventBus.emit<NotificationSendEvent>({
        type: 'notification:send',
        recipient: 'bob@example.com',
        subject: 'Normal Notification',
        body: 'Goes to email by priority',
        priority: 'normal',
        timestamp: new Date(),
      });

      expect(emailChannel.getSentEmails()).toHaveLength(1);
      expect(smsChannel.getSentMessages()).toHaveLength(0);
    });

    it('should fall back to priority routing when preferred channel is not found', async () => {
      preferencesService.setPreference('alice@example.com', 'push');

      await eventBus.emit<NotificationSendEvent>({
        type: 'notification:send',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test body',
        priority: 'urgent',
        timestamp: new Date(),
      });

      // 'push' channel doesn't exist, falls back to priority routing (urgent → sms)
      expect(smsChannel.getSentMessages()).toHaveLength(1);
      expect(emailChannel.getSentEmails()).toHaveLength(0);
    });

    it('should revert to priority routing after removing preference', async () => {
      preferencesService.setPreference('alice@example.com', 'webhook');
      preferencesService.removePreference('alice@example.com');

      await eventBus.emit<NotificationSendEvent>({
        type: 'notification:send',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test body',
        priority: 'normal',
        timestamp: new Date(),
      });

      // Back to priority routing: normal → email
      expect(emailChannel.getSentEmails()).toHaveLength(1);
      expect(webhookChannel.getDeliveries()).toHaveLength(0);
    });
  });

  describe('audit logging', () => {
    it('should record an audit entry for each dispatched notification', async () => {
      await eventBus.emit<NotificationSendEvent>({
        type: 'notification:send',
        recipient: 'alice@example.com',
        subject: 'Test Subject',
        body: 'Test body',
        priority: 'normal',
        timestamp: new Date(),
      });

      const entries = auditService.getEntries();
      expect(entries).toHaveLength(1);
      expect(entries[0]?.notificationId).toBe('notif-0001');
      expect(entries[0]?.recipient).toBe('alice@example.com');
      expect(entries[0]?.channel).toBe('email');
      expect(entries[0]?.priority).toBe('normal');
      expect(entries[0]?.routingReason).toBe('priority');
    });

    it('should record user-preference as routing reason when applicable', async () => {
      preferencesService.setPreference('alice@example.com', 'webhook');

      await eventBus.emit<NotificationSendEvent>({
        type: 'notification:send',
        recipient: 'alice@example.com',
        subject: 'Preferred Channel',
        body: 'Goes to webhook by preference',
        priority: 'urgent',
        timestamp: new Date(),
      });

      const entries = auditService.getEntries();
      expect(entries).toHaveLength(1);
      expect(entries[0]?.channel).toBe('webhook');
      expect(entries[0]?.priority).toBe('urgent');
      expect(entries[0]?.routingReason).toBe('user-preference');
    });

    it('should record multiple audit entries for multiple notifications', async () => {
      await eventBus.emit<NotificationSendEvent>({
        type: 'notification:send',
        recipient: 'alice@example.com',
        subject: 'First',
        body: 'First notification',
        priority: 'urgent',
        timestamp: new Date(),
      });

      await eventBus.emit<NotificationSendEvent>({
        type: 'notification:send',
        recipient: 'bob@example.com',
        subject: 'Second',
        body: 'Second notification',
        priority: 'low',
        timestamp: new Date(),
      });

      const entries = auditService.getEntries();
      expect(entries).toHaveLength(2);
      expect(entries[0]?.channel).toBe('sms');
      expect(entries[1]?.channel).toBe('webhook');
    });

    it('should allow querying audit entries by recipient', async () => {
      await eventBus.emit<NotificationSendEvent>({
        type: 'notification:send',
        recipient: 'alice@example.com',
        subject: 'For Alice',
        body: 'Body',
        priority: 'normal',
        timestamp: new Date(),
      });

      await eventBus.emit<NotificationSendEvent>({
        type: 'notification:send',
        recipient: 'bob@example.com',
        subject: 'For Bob',
        body: 'Body',
        priority: 'urgent',
        timestamp: new Date(),
      });

      expect(auditService.getEntriesForRecipient('alice@example.com')).toHaveLength(1);
      expect(auditService.getEntriesForRecipient('bob@example.com')).toHaveLength(1);
      expect(auditService.getEntriesForRecipient('charlie@example.com')).toHaveLength(0);
    });

    it('should allow querying audit entries by channel', async () => {
      await eventBus.emit<NotificationSendEvent>({
        type: 'notification:send',
        recipient: 'a@example.com',
        subject: 'Urgent',
        body: 'Body',
        priority: 'urgent',
        timestamp: new Date(),
      });

      await eventBus.emit<NotificationSendEvent>({
        type: 'notification:send',
        recipient: 'b@example.com',
        subject: 'Normal',
        body: 'Body',
        priority: 'normal',
        timestamp: new Date(),
      });

      expect(auditService.getEntriesForChannel('sms')).toHaveLength(1);
      expect(auditService.getEntriesForChannel('email')).toHaveLength(1);
      expect(auditService.getEntriesForChannel('webhook')).toHaveLength(0);
    });
  });

  describe('full flow: event → priority routing → channel → audit', () => {
    it('should route order creation through full pipeline with default normal priority', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-100',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 3, unitPrice: 15 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Normal priority → email channel
      expect(emailChannel.getSentEmails()).toHaveLength(1);
      expect(emailChannel.getSentEmails()[0]?.subject).toContain('Order Confirmation');
      expect(smsChannel.getSentMessages()).toHaveLength(0);

      // Audit recorded
      const auditEntries = auditService.getEntries();
      expect(auditEntries).toHaveLength(1);
      expect(auditEntries[0]?.channel).toBe('email');
      expect(auditEntries[0]?.priority).toBe('normal');
      expect(auditEntries[0]?.routingReason).toBe('priority');
    });

    it('should respect user preference override in full pipeline', async () => {
      preferencesService.setPreference('alice@example.com', 'sms');

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-200',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Gadget', quantity: 1, unitPrice: 99 },
          ],
          total: 99,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // User preference overrides: goes to SMS instead of email
      expect(smsChannel.getSentMessages()).toHaveLength(1);
      expect(smsChannel.getSentMessages()[0]?.subject).toContain('Order Confirmation');
      expect(emailChannel.getSentEmails()).toHaveLength(0);

      // Audit reflects user-preference routing
      const auditEntries = auditService.getEntries();
      expect(auditEntries).toHaveLength(1);
      expect(auditEntries[0]?.channel).toBe('sms');
      expect(auditEntries[0]?.routingReason).toBe('user-preference');
    });

    it('should handle multiple notifications with mixed routing', async () => {
      preferencesService.setPreference('bob@example.com', 'webhook');

      // Urgent notification for alice (no preference) → SMS by priority
      await eventBus.emit<NotificationSendEvent>({
        type: 'notification:send',
        recipient: 'alice@example.com',
        subject: 'Urgent for Alice',
        body: 'Urgent body',
        priority: 'urgent',
        timestamp: new Date(),
      });

      // Normal notification for bob (has webhook preference) → webhook by preference
      await eventBus.emit<NotificationSendEvent>({
        type: 'notification:send',
        recipient: 'bob@example.com',
        subject: 'Normal for Bob',
        body: 'Normal body',
        priority: 'normal',
        timestamp: new Date(),
      });

      // Low notification for charlie (no preference) → webhook by priority
      await eventBus.emit<NotificationSendEvent>({
        type: 'notification:send',
        recipient: 'charlie@example.com',
        subject: 'Low for Charlie',
        body: 'Low body',
        priority: 'low',
        timestamp: new Date(),
      });

      expect(smsChannel.getSentMessages()).toHaveLength(1);
      expect(emailChannel.getSentEmails()).toHaveLength(0);
      expect(webhookChannel.getDeliveries()).toHaveLength(2);

      const entries = auditService.getEntries();
      expect(entries).toHaveLength(3);
      expect(entries[0]?.routingReason).toBe('priority');
      expect(entries[0]?.channel).toBe('sms');
      expect(entries[1]?.routingReason).toBe('user-preference');
      expect(entries[1]?.channel).toBe('webhook');
      expect(entries[2]?.routingReason).toBe('priority');
      expect(entries[2]?.channel).toBe('webhook');
    });
  });
});

